#include <stdio.h>
#include <stdlib.h>

// Structure to represent a citizen
typedef struct Citizen {
    int wealth;
} Citizen;

// Comparison function for the priority queue
int compare(const void *a, const void *b) {
    Citizen *citizenA = (Citizen *)a;
    Citizen *citizenB = (Citizen *)b;
    return citizenB->wealth - citizenA->wealth;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Citizen *citizens = (Citizen *)malloc(N * sizeof(Citizen));
    int *kingVisits = (int *)malloc(M * sizeof(int));
    int citizenIndex = 0;
    int kingVisitIndex = 0;
    int queueSize = 0;
    Citizen *queue = (Citizen *)malloc(M * sizeof(Citizen));

    for (int i = 0; i < N + M; i++) {
        int input;
        scanf("%d", &input);
        if (input == -1) {
            // King's visit
            kingVisits[kingVisitIndex++] = queueSize;
        } else {
            // Citizen's visit
            citizens[citizenIndex].wealth = input;
            queue[queueSize].wealth = input;
            queueSize++;
            qsort(queue, queueSize, sizeof(Citizen), compare);
            citizenIndex++;
        }
    }

    for (int i = 0; i < M; i++) {
        printf("%d\n", queue[kingVisits[i]].wealth);
    }

    free(citizens);
    free(kingVisits);
    free(queue);
    return 0;
}

